import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.BS3ZfcoS.js";const u=JSON.parse('{"title":"年轻人赚到第一桶金","description":"","frontmatter":{"title":"年轻人赚到第一桶金","author":"","collection":"职场成长","series_order":10,"total_chars":719},"headers":[],"relativePath":"career/first-pot-of-gold.md","filePath":"career/first-pot-of-gold.md"}'),s={name:"career/first-pot-of-gold.md"};function p(n,a,i,l,h,d){return r(),e("div",null,[...a[0]||(a[0]=[o('<h2 id="s-543" tabindex="-1">年轻人赚到第一桶金系列 <a class="header-anchor" href="#s-543" aria-label="Permalink to &quot;年轻人赚到第一桶金系列 {#s-543}&quot;">​</a></h2><p>共3个视频</p><h3 id="s-544" tabindex="-1">年轻人如何快速赚到第一桶金（一）——专业路线 <a class="header-anchor" href="#s-544" aria-label="Permalink to &quot;年轻人如何快速赚到第一桶金（一）——专业路线 {#s-544}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **专业路线——靠自己的专业能力赚钱（如口译家教200元/时），比父母给的生活费多得多</p><p>**2. **两个关键点：拿得出成绩/作品证明专业实力；具备差异化优势（如为学生定制追星背单词表）</p><p>**3. **不适合直接变现的专业可发展兴趣爱好——如摄影从兴趣到接单到开工作室买车买房</p><p><strong>金句</strong></p><p><em>「如果我要靠自己的专业吃饭，我每次服务我的客户的目的就是让她愿意下一次还找到我」</em></p><p><strong>行动指南</strong></p><p>梳理自己的专业技能或兴趣，提供差异化服务建立口碑</p><h3 id="s-545" tabindex="-1">年轻人如何快速赚到第一桶金（二）——商业路线·校徽戒指 <a class="header-anchor" href="#s-545" aria-label="Permalink to &quot;年轻人如何快速赚到第一桶金（二）——商业路线·校徽戒指 {#s-545}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-546" tabindex="-1">1. 商业路线——从情感需求出发做产品；校徽戒指案例：毕业生想带走母校情结 <a class="header-anchor" href="#s-546" aria-label="Permalink to &quot;1. 商业路线——从情感需求出发做产品；校徽戒指案例：毕业生想带走母校情结 {#s-546}&quot;">​</a></h4><p>**2. **关键步骤：验证需求（发说说获预售）→定价测试（问学长愿意出多少钱）→控制成本（5-8元）→合理定价（19.9元）→快速复制到其他学校</p><p>**3. **短短两三周出了4000多枚，8个学校卖25000-28000枚，净赚4-5万</p><p><strong>金句</strong></p><p><em>「每个人他大学走的时候，他都想要带走一点情节」</em></p><p><strong>行动指南</strong></p><p>从身边情感需求切入，小规模验证后快速复制</p><h3 id="s-547" tabindex="-1">年轻人如何快速赚到第一桶金（三）——商业路线·资源合作 <a class="header-anchor" href="#s-547" aria-label="Permalink to &quot;年轻人如何快速赚到第一桶金（三）——商业路线·资源合作 {#s-547}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **利用学生的独特身份和校园资源与外部商家合作（如帮阿里推广下载量，创造3-40万收益）</p><h4 id="s-548" tabindex="-1">2. 建立创业者圈子——校内各校创业朋友组成分销网络 <a class="header-anchor" href="#s-548" aria-label="Permalink to &quot;2. 建立创业者圈子——校内各校创业朋友组成分销网络 {#s-548}&quot;">​</a></h4><h4 id="s-549" tabindex="-1">3. 从低成本小生意起步建立&quot;创业者&quot;个人标签，自然进入相关圈子 <a class="header-anchor" href="#s-549" aria-label="Permalink to &quot;3. 从低成本小生意起步建立&quot;创业者&quot;个人标签，自然进入相关圈子 {#s-549}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「我们作为学生是有一些独特的优势和资源在的」</em></p><p><strong>行动指南</strong></p><p>先做小生意建立创业者标签，积累人脉后做更大项目</p>',29)])])}const f=t(s,[["render",p]]);export{u as __pageData,f as default};
